INSERT INTO questions (id, text, options, "correctIndex", branch, difficulty, category, explanation, "statPrimary") VALUES
(gen_random_uuid(), 'Какой элемент таблицы Менделеева имеет символ Au?', '["Серебро","Золото","Алюминий","Аргон"]', 1, 'ERUDITION', 'BRONZE', 'Химия', 'Au — от латинского Aurum, означающего золото.', 'eruditionXp'),
(gen_random_uuid(), 'В каком году человек впервые высадился на Луну?', '["1965","1969","1971","1973"]', 1, 'ERUDITION', 'BRONZE', 'История', 'Нил Армстронг ступил на поверхность Луны 20 июля 1969 года в рамках миссии «Аполлон-11».', 'eruditionXp'),
(gen_random_uuid(), 'Столица Австралии — это:', '["Сидней","Мельбурн","Канберра","Брисбен"]', 2, 'ERUDITION', 'BRONZE', 'География', 'Канберра была специально построена как столица в 1913 году, чтобы разрешить спор между Сиднеем и Мельбурном.', 'eruditionXp'),
(gen_random_uuid(), 'Кто написал «Войну и мир»?', '["Достоевский","Толстой","Чехов","Тургенев"]', 1, 'ERUDITION', 'BRONZE', 'Литература', 'Лев Николаевич Толстой написал роман-эпопею «Война и мир» в 1863-1869 годах.', 'eruditionXp'),
(gen_random_uuid(), 'Какая планета Солнечной системы самая большая?', '["Сатурн","Юпитер","Нептун","Уран"]', 1, 'ERUDITION', 'BRONZE', 'Астрономия', 'Юпитер — газовый гигант, его масса в 318 раз превышает массу Земли.', 'eruditionXp'),
(gen_random_uuid(), 'Какой газ составляет большую часть атмосферы Земли?', '["Кислород","Углекислый газ","Азот","Аргон"]', 2, 'ERUDITION', 'SILVER', 'Химия', 'Азот составляет около 78% атмосферы, кислород — около 21%.', 'eruditionXp'),
(gen_random_uuid(), 'Кто открыл пенициллин?', '["Пастер","Флеминг","Кох","Дженнер"]', 1, 'ERUDITION', 'SILVER', 'Биология', 'Александр Флеминг обнаружил антибактериальные свойства пенициллина в 1928 году.', 'eruditionXp'),
(gen_random_uuid(), 'Какая река самая длинная в мире?', '["Амазонка","Нил","Янцзы","Миссисипи"]', 1, 'ERUDITION', 'SILVER', 'География', 'Нил традиционно считается самой длинной рекой — около 6650 км, хотя Амазонка может быть длиннее.', 'eruditionXp'),
(gen_random_uuid(), 'В каком году началась Первая мировая война?', '["1912","1914","1916","1918"]', 1, 'ERUDITION', 'SILVER', 'История', 'Первая мировая война началась 28 июля 1914 года после убийства эрцгерцога Франца Фердинанда.', 'eruditionXp'),
(gen_random_uuid(), 'Какой учёный сформулировал теорию относительности?', '["Ньютон","Эйнштейн","Бор","Планк"]', 1, 'ERUDITION', 'SILVER', 'Физика', 'Альберт Эйнштейн опубликовал специальную теорию относительности в 1905 году, общую — в 1915.', 'eruditionXp'),
(gen_random_uuid(), 'Какой философ написал «Государство»?', '["Аристотель","Платон","Сократ","Сенека"]', 1, 'ERUDITION', 'GOLD', 'Философия', 'Платон написал диалог «Государство» около 375 г. до н.э., где описал идеальное государство.', 'eruditionXp'),
(gen_random_uuid(), 'Какой элемент имеет наибольшую электроотрицательность?', '["Кислород","Хлор","Фтор","Азот"]', 2, 'ERUDITION', 'GOLD', 'Химия', 'Фтор имеет электроотрицательность 3.98 по шкале Полинга — максимум среди всех элементов.', 'eruditionXp'),
(gen_random_uuid(), 'Какой древний город был засыпан извержением Везувия в 79 году н.э.?', '["Рим","Помпеи","Карфаген","Афины"]', 1, 'ERUDITION', 'GOLD', 'История', 'Помпеи были погребены под слоем вулканического пепла, что сохранило город для археологов.', 'eruditionXp'),
(gen_random_uuid(), 'Кто автор «Божественной комедии»?', '["Петрарка","Данте","Боккаччо","Вергилий"]', 1, 'ERUDITION', 'GOLD', 'Литература', 'Данте Алигьери написал «Божественную комедию» в 1308-1321 годах.', 'eruditionXp'),
(gen_random_uuid(), 'Термин «парадигма» в науку ввёл:', '["Поппер","Кун","Лакатос","Фейерабенд"]', 1, 'ERUDITION', 'GOLD', 'Философия', 'Томас Кун ввёл понятие научной парадигмы в книге «Структура научных революций» (1962).', 'eruditionXp');
INSERT INTO questions (id, text, options, "correctIndex", branch, difficulty, category, explanation, "statPrimary") VALUES
(gen_random_uuid(), 'Что такое «аргумент к авторитету»?', '["Ссылка на мнение эксперта вместо доказательства","Логическое доказательство","Эмоциональное убеждение","Статистический довод"]', 0, 'RHETORIC', 'BRONZE', 'Логические ошибки', 'Аргумент к авторитету — логическая ошибка, когда мнение авторитета подменяет собой доказательство.', 'rhetoricXp'),
(gen_random_uuid(), 'Какой приём речи использует повторение начала фраз?', '["Метафора","Анафора","Эпифора","Антитеза"]', 1, 'RHETORIC', 'BRONZE', 'Риторические приёмы', 'Анафора — стилистическая фигура, повторение начальных слов в последовательных фразах.', 'rhetoricXp'),
(gen_random_uuid(), 'Что означает «ad hominem» в споре?', '["Атака на личность оппонента","Обращение к чувствам","Подмена тезиса","Ложная дилемма"]', 0, 'RHETORIC', 'BRONZE', 'Логические ошибки', 'Ad hominem — переход на личности вместо опровержения аргументов.', 'rhetoricXp'),
(gen_random_uuid(), 'Кто считается отцом риторики?', '["Сократ","Аристотель","Цицерон","Демосфен"]', 1, 'RHETORIC', 'BRONZE', 'История риторики', 'Аристотель написал трактат «Риторика», систематизировав искусство убеждения.', 'rhetoricXp'),
(gen_random_uuid(), '«Соломенное чучело» в аргументации — это:', '["Искажение позиции оппонента для лёгкого опровержения","Сильный аргумент","Отвлекающий манёвр","Доказательство от противного"]', 0, 'RHETORIC', 'BRONZE', 'Логические ошибки', 'Straw man — подмена реальной позиции оппонента упрощённой версией, которую легко опровергнуть.', 'rhetoricXp'),
(gen_random_uuid(), 'Что такое «красная селёдка» (red herring) в аргументации?', '["Отвлечение от основной темы","Подмена понятий","Апелляция к эмоциям","Круговая аргументация"]', 0, 'RHETORIC', 'SILVER', 'Логические ошибки', 'Red herring — введение не относящейся к делу информации для отвлечения от сути дискуссии.', 'rhetoricXp'),
(gen_random_uuid(), 'Принцип «бремя доказательства» означает:', '["Доказывает тот, кто утверждает","Доказывает тот, кто опровергает","Оба должны доказать","Доказательства не нужны"]', 0, 'RHETORIC', 'SILVER', 'Аргументация', 'Бремя доказательства лежит на том, кто выдвигает утверждение, а не на том, кто его оспаривает.', 'rhetoricXp'),
(gen_random_uuid(), 'Что такое «ложная дилемма»?', '["Представление только двух вариантов, когда их больше","Неверная статистика","Подмена тезиса","Аргумент к жалости"]', 0, 'RHETORIC', 'SILVER', 'Логические ошибки', 'Ложная дилемма — представление ситуации как выбора между двумя крайностями, игнорируя другие варианты.', 'rhetoricXp'),
(gen_random_uuid(), 'Какой тип аргумента использует аналогию?', '["Дедуктивный","Индуктивный","Аргумент по аналогии","Абдуктивный"]', 2, 'RHETORIC', 'SILVER', 'Аргументация', 'Аргумент по аналогии переносит свойства одного объекта на другой на основании их сходства.', 'rhetoricXp'),
(gen_random_uuid(), 'Какой из этих приёмов является манипулятивным?', '["Framing — подача информации в определённой рамке","Предоставление полных данных","Открытые вопросы","Признание ошибки"]', 0, 'RHETORIC', 'SILVER', 'Манипуляции', 'Framing — подача одной и той же информации в разном контексте для влияния на восприятие.', 'rhetoricXp'),
(gen_random_uuid(), '«Окно Овертона» описывает:', '["Сдвиг границ приемлемости идей в обществе","Метод ведения переговоров","Структуру убедительной речи","Технику запоминания"]', 0, 'RHETORIC', 'GOLD', 'Манипуляции', 'Окно Овертона — модель, описывающая спектр идей от немыслимых до принятых обществом.', 'rhetoricXp'),
(gen_random_uuid(), 'Эффект Даннинга-Крюгера описывает:', '["Переоценку компетентности некомпетентными людьми","Влияние первого впечатления","Искажение памяти","Групповое мышление"]', 0, 'RHETORIC', 'GOLD', 'Когнитивные искажения', 'Некомпетентные люди склонны переоценивать свои способности, а эксперты — недооценивать.', 'rhetoricXp'),
(gen_random_uuid(), 'Что такое «апелляция к природе»?', '["Утверждение что естественное = хорошее","Научный аргумент","Экологический довод","Эволюционный подход"]', 0, 'RHETORIC', 'GOLD', 'Логические ошибки', 'Appeal to nature — ошибочное предположение, что всё натуральное автоматически полезно или правильно.', 'rhetoricXp'),
(gen_random_uuid(), 'Метод Сократа в диалоге основан на:', '["Задавании последовательных вопросов для выявления противоречий","Монологе","Эмоциональном давлении","Авторитетном утверждении"]', 0, 'RHETORIC', 'GOLD', 'Методы аргументации', 'Сократический метод — серия вопросов, подводящих собеседника к самостоятельному обнаружению истины.', 'rhetoricXp'),
(gen_random_uuid(), 'Принцип фальсифицируемости Поппера утверждает, что:', '["Научная теория должна быть опровергаемой в принципе","Все теории ложны","Наука невозможна","Эксперименты бессмысленны"]', 0, 'RHETORIC', 'GOLD', 'Философия науки', 'По Попперу, теория научна только если можно представить эксперимент, который её опровергнет.', 'rhetoricXp');
INSERT INTO questions (id, text, options, "correctIndex", branch, difficulty, category, explanation, "statPrimary") VALUES
(gen_random_uuid(), 'Что такое «эвристика доступности»?', '["Оценка вероятности по лёгкости припоминания примеров","Метод решения задач","Стратегия обучения","Тип памяти"]', 0, 'INTUITION', 'BRONZE', 'Когнитивные искажения', 'Мы оцениваем вероятность события по тому, как легко вспоминаем похожие случаи.', 'intuitionXp'),
(gen_random_uuid(), '«Эффект якоря» — это:', '["Чрезмерная зависимость от первой полученной информации","Запоминание первого элемента","Сопротивление изменениям","Привязанность к месту"]', 0, 'INTUITION', 'BRONZE', 'Когнитивные искажения', 'Первая названная цифра или факт «якорит» дальнейшие суждения, даже если она произвольна.', 'intuitionXp'),
(gen_random_uuid(), 'Интуиция в психологии — это:', '["Быстрое принятие решений на основе паттернов опыта","Сверхъестественная способность","Случайное угадывание","Математический расчёт"]', 0, 'INTUITION', 'BRONZE', 'Психология', 'Интуиция — результат бессознательной обработки накопленного опыта, а не мистика.', 'intuitionXp'),
(gen_random_uuid(), '«Предвзятость подтверждения» означает:', '["Поиск информации, подтверждающей имеющееся мнение","Объективный анализ","Отрицание фактов","Согласие с большинством"]', 0, 'INTUITION', 'BRONZE', 'Когнитивные искажения', 'Мы склонны искать и запоминать информацию, которая подтверждает наши существующие убеждения.', 'intuitionXp'),
(gen_random_uuid(), 'Что такое «ошибка игрока» (gamblers fallacy)?', '["Вера что после серии одинаковых событий следующее будет другим","Жадность","Неумение считать","Суеверие"]', 0, 'INTUITION', 'BRONZE', 'Вероятности', 'Каждый бросок монеты независим — предыдущие результаты не влияют на следующий.', 'intuitionXp'),
(gen_random_uuid(), 'Система 1 по Канеману — это:', '["Быстрое, автоматическое мышление","Медленное, аналитическое мышление","Творческое мышление","Логическое мышление"]', 0, 'INTUITION', 'SILVER', 'Психология', 'Канеман выделил Систему 1 (быструю, интуитивную) и Систему 2 (медленную, рациональную).', 'intuitionXp'),
(gen_random_uuid(), '«Эффект фрейминга» означает, что:', '["Решение зависит от формулировки проблемы","Рамка улучшает картину","Ограничения помогают","Структура важнее содержания"]', 0, 'INTUITION', 'SILVER', 'Когнитивные искажения', '«90% выживаемость» и «10% смертность» — одно и то же, но воспринимается по-разному.', 'intuitionXp'),
(gen_random_uuid(), 'Парадокс Монти Холла демонстрирует, что:', '["Смена выбора увеличивает вероятность выигрыша до 2/3","Все двери равновероятны","Интуиция всегда верна","Менять выбор бессмысленно"]', 0, 'INTUITION', 'SILVER', 'Вероятности', 'После открытия пустой двери ведущим смена выбора даёт 2/3 шанса выиграть.', 'intuitionXp'),
(gen_random_uuid(), '«Ретроспективное искажение» (hindsight bias) — это:', '["Ощущение что событие было предсказуемо после того, как оно произошло","Память о прошлом","Предсказание будущего","Планирование"]', 0, 'INTUITION', 'SILVER', 'Когнитивные искажения', 'После события мы искажённо полагаем, что «знали это заранее».', 'intuitionXp'),
(gen_random_uuid(), 'Что такое «эффект ореола»?', '["Общее впечатление влияет на оценку конкретных качеств","Свечение вокруг предмета","Визуальная иллюзия","Эффект новизны"]', 0, 'INTUITION', 'SILVER', 'Когнитивные искажения', 'Положительное первое впечатление заставляет оценивать все качества человека выше.', 'intuitionXp'),
(gen_random_uuid(), 'Байесовское мышление предполагает:', '["Обновление вероятностей при получении новой информации","Только дедуктивные выводы","Игнорирование предыдущего опыта","Полагание на интуицию"]', 0, 'INTUITION', 'GOLD', 'Вероятности', 'Теорема Байеса позволяет пересчитывать вероятность гипотезы по мере поступления данных.', 'intuitionXp'),
(gen_random_uuid(), '«Чёрный лебедь» по Талебу — это:', '["Крайне маловероятное событие с огромным влиянием","Редкая птица","Финансовый инструмент","Тип стратегии"]', 0, 'INTUITION', 'GOLD', 'Принятие решений', 'Нассим Талеб описал «чёрных лебедей» — редкие, непредсказуемые события с колоссальными последствиями.', 'intuitionXp'),
(gen_random_uuid(), 'Принцип Линди утверждает, что:', '["Чем дольше что-то существует, тем дольше проживёт","Всё устаревает","Новое лучше старого","Технологии ускоряются"]', 0, 'INTUITION', 'GOLD', 'Принятие решений', 'Для нескоропортящихся вещей (идей, книг, технологий) ожидаемая продолжительность жизни пропорциональна текущему возрасту.', 'intuitionXp'),
(gen_random_uuid(), '«Ошибка базового процента» (base rate neglect) — это:', '["Игнорирование общей статистики в пользу конкретного случая","Неверный подсчёт","Незнание математики","Ошибка выборки"]', 0, 'INTUITION', 'GOLD', 'Когнитивные искажения', 'Люди часто игнорируют базовую статистику, фокусируясь на яркости конкретного случая.', 'intuitionXp'),
(gen_random_uuid(), '«Via negativa» в принятии решений означает:', '["Улучшение через устранение, а не добавление","Пессимистичный подход","Отказ от действий","Негативное мышление"]', 0, 'INTUITION', 'GOLD', 'Принятие решений', 'Часто эффективнее убрать вредное, чем добавить полезное — принцип из книг Талеба.', 'intuitionXp');
